    headerTitle: { fontSize: 20, fontWeight: '700', color: Colors.gray[900] },
    scrollContent: { padding: 20, paddingBottom: 100 },
    section: { marginBottom: 24 },
    label: { fontSize: 16, fontWeight: '600', color: Colors.gray[900], marginBottom: 12 },
    helperText: { fontSize: 14, color: Colors.gray[500], marginBottom: 12, marginTop: -8 },
    input: {
        backgroundColor: Colors.gray[50],
        borderWidth: 1,
        borderColor: Colors.gray[200],
        borderRadius: 12,
        padding: 16,
        fontSize: 16,
        color: Colors.gray[900],
    },
    memberRow: {
        flexDirection: 'row',
        alignItems: 'center',
        marginBottom: 12,
    },
    memberInput: {
        flex: 1,
        backgroundColor: Colors.gray[50],
        borderWidth: 1,
        borderColor: Colors.gray[200],
        borderRadius: 12,
        padding: 14,
        fontSize: 16,
        color: Colors.gray[900],
    },
    removeBtn: {
        padding: 10,
        marginLeft: 8,
    },
    addMemberBtn: {
        flexDirection: 'row',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 16,
        borderWidth: 1,
        borderColor: Colors.primary[200],
        borderRadius: 12,
        borderStyle: 'dashed',
        backgroundColor: Colors.primary[50],
    },
    addMemberText: {
        marginLeft: 8,
        fontSize: 16,
        fontWeight: '600',
        color: Colors.primary[600],
    },
    footer: {
        position: 'absolute',
        bottom: 0,
        left: 0,
        right: 0,
        backgroundColor: Colors.white,
        padding: 20,
        borderTopWidth: 1,
        borderTopColor: Colors.gray[100],
    },
    saveBtn: {
        backgroundColor: Colors.primary[600],
        borderRadius: 16,
        paddingVertical: 18,
        alignItems: 'center',
    },
    saveBtnDisabled: {
        backgroundColor: Colors.primary[300],
    },
    saveBtnText: {
        color: 'white',
        fontSize: 16,
        fontWeight: 'bold',
    },
});

