        borderRadius: 16,
        backgroundColor: '#e5e7eb',
        marginRight: 12,
    },
    itemText: {
        fontSize: 16,
        flex: 1,
    },
    backButton: {
        padding: 12,
        paddingHorizontal: 16,
        backgroundColor: '#eff6ff',
    }
});

import React, { useRef, useEffect } from 'react';
import { 
  View, 
  Text, 
  TextInput, 
  StyleSheet, 
  Animated, 
  TouchableOpacity, 
  KeyboardTypeOptions 
} from 'react-native';
import { Colors, Typography, Layout } from '../constants/Theme';

interface FormFieldProps {
  label: string;
  value: string;
  onChangeText?: (text: string) => void;
  error?: string;
  placeholder?: string;
  rightElement?: React.ReactNode;
  onPress?: () => void;
  required?: boolean;
  keyboardType?: KeyboardTypeOptions;
  multiline?: boolean;
  editable?: boolean;
  children?: React.ReactNode;
}

export const FormField: React.FC<FormFieldProps> = ({
  label,
  value,
  onChangeText,
  error,
  placeholder,
  rightElement,
  onPress,
  required,
  keyboardType = 'default',
  multiline = false,
  editable = true,
  children
}) => {
  const borderColor = useRef(new Animated.Value(0)).current; // 0: default, 1: focus, 2: error
  const errorOpacity = useRef(new Animated.Value(0)).current;
  const errorTranslateY = useRef(new Animated.Value(-4)).current;

  useEffect(() => {
    if (error) {
      Animated.parallel([
        Animated.timing(borderColor, {
          toValue: 2,
          duration: 200,
          useNativeDriver: false,
        }),
        Animated.spring(errorOpacity, {
          toValue: 1,
          useNativeDriver: true,
        }),
        Animated.spring(errorTranslateY, {
          toValue: 0,
          useNativeDriver: true,
        }),
      ]).start();
    } else {
      Animated.parallel([
        Animated.timing(borderColor, {
          toValue: 0,
          duration: 200,
          useNativeDriver: false,
        }),
        Animated.timing(errorOpacity, {
          toValue: 0,
          duration: 150,
          useNativeDriver: true,
        }),
      ]).start();
    }
  }, [borderColor, error, errorOpacity, errorTranslateY]);

  const onFocus = () => {
    if (!error) {
      Animated.timing(borderColor, {
        toValue: 1,
        duration: 200,
        useNativeDriver: false,
      }).start();
    }
  };

  const onBlur = () => {
    if (!error) {
      Animated.timing(borderColor, {
        toValue: 0,
        duration: 200,
        useNativeDriver: false,
      }).start();
    }
  };

  const animatedBorderColor = borderColor.interpolate({
    inputRange: [0, 1, 2],
    outputRange: [Colors.gray[200], Colors.primary[600], '#F04438'],
  });

  const animatedBorderWidth = borderColor.interpolate({
    inputRange: [0, 1, 2],
    outputRange: [1, 1.5, 1.5],
  });

  return (
    <View style={styles.container}>
      <View style={styles.labelRow}>
        <Text style={styles.label}>{label}</Text>
        {required && <Text style={styles.required}>*</Text>}
      </View>

      <Animated.View 
        style={[
          styles.inputContainer, 
          { 
            borderColor: animatedBorderColor,
            borderWidth: animatedBorderWidth
          }
        ]}
      >
        {children ? (
          <View style={styles.childrenContainer}>{children}</View>
        ) : onPress ? (
          <TouchableOpacity style={styles.pressable} onPress={onPress} activeOpacity={0.7}>
            <Text 
              style={[
                styles.inputText, 
                !value && { color: Colors.gray[400] }
              ]}
              numberOfLines={1}
            >
              {value || placeholder}
            </Text>
            {rightElement}
          </TouchableOpacity>
        ) : (
          <View style={styles.inputWrapper}>
            <TextInput
              style={styles.input}
              value={value}
              onChangeText={onChangeText}
              placeholder={placeholder}
              placeholderTextColor={Colors.gray[400]}
              onFocus={onFocus}
              onBlur={onBlur}
              keyboardType={keyboardType}
              multiline={multiline}
              editable={editable}
            />
            {rightElement}
          </View>
        )}
      </Animated.View>

      {error && (
        <Animated.View 
          style={[
            styles.errorContainer, 
            { opacity: errorOpacity, transform: [{ translateY: errorTranslateY }] }
          ]}
        >
          <Text style={styles.errorText}>⚠ {error}</Text>
        </Animated.View>
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    marginBottom: 16,
    width: '100%',
  },
  labelRow: {
    flexDirection: 'row',
    marginBottom: 6,
    alignItems: 'center',
  },
  label: {
    fontSize: Typography.size.xs,
    fontFamily: Typography.family.bold,
    color: Colors.gray[500],
    textTransform: 'uppercase',
    letterSpacing: 0.5,
  },
  required: {
    color: '#F04438',
    marginLeft: 2,
    fontSize: Typography.size.xs,
    fontFamily: Typography.family.bold,
  },
  inputContainer: {
    height: 52,
    backgroundColor: Colors.gray[100],
    borderRadius: Layout.radius.md,
    overflow: 'hidden',
    justifyContent: 'center',
  },
  inputWrapper: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingHorizontal: 14,
    flex: 1,
  },
  input: {
    flex: 1,
    height: '100%',
    fontSize: Typography.size.md,
    fontFamily: Typography.family.medium,
    color: Colors.gray[900],
  },
  pressable: {
    flex: 1,
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    paddingHorizontal: 14,
  },
  inputText: {
    fontSize: Typography.size.md,
    fontFamily: Typography.family.medium,
    color: Colors.gray[900],
    flex: 1,
  },
  childrenContainer: {
    flex: 1,
  },
  errorContainer: {
    marginTop: 4,
    paddingHorizontal: 4,
  },
  errorText: {
    fontSize: Typography.size.xs,
    fontFamily: Typography.family.medium,
    color: '#F04438',
  },
});

import React, { useMemo } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, Dimensions } from 'react-native';
import { format, startOfMonth, endOfMonth, eachDayOfInterval, isSameDay, getDay } from 'date-fns';
import { Colors } from '../constants/Theme';
import { Transaction } from '../services/database';

interface HeatmapCalendarProps {
    month: Date;
    transactions: Transaction[];
    onDayPress: (date: Date) => void;
    selectedDate: Date;
}

const screenWidth = Dimensions.get('window').width;
const cellSize = (screenWidth - 40) / 7; // 40 = padding

export const HeatmapCalendar: React.FC<HeatmapCalendarProps> = ({ month, transactions, onDayPress, selectedDate }) => {

    // 1. Calculate Daily Totals & Max Spend
    const { dailyMap, maxSpend } = useMemo(() => {
        const map = new Map<string, number>();
        let max = 0;

        transactions.forEach(t => {
            const isExpense = t.type === 'expense'
                || (!t.type && t.category !== 'Income' && t.category !== 'Transfer' && t.category !== 'Debt/Credit');
            if (!isExpense) return;
            const key = format(new Date(t.date), 'yyyy-MM-dd');
            const newTotal = (map.get(key) || 0) + t.amount;
            map.set(key, newTotal);
            if (newTotal > max) max = newTotal;
        });

        return { dailyMap: map, maxSpend: max };
    }, [transactions]);

    // 2. Generate Days
    const days = useMemo(() => {
        const start = startOfMonth(month);
        const end = endOfMonth(month);
        return eachDayOfInterval({ start, end });
    }, [month]);

    // 3. Get Color Intensity
    const getIntensityColor = (date: Date) => {
        const key = format(date, 'yyyy-MM-dd');
        const amount = dailyMap.get(key) || 0;

        if (amount === 0) return Colors.gray[100]; // No spend

        const intensity = maxSpend > 0 ? amount / maxSpend : 0;

        // Interpolate between light and dark brand color
        // Simple distinct levels for better readability on small screens
        if (intensity > 0.8) return Colors.primary[900];
        if (intensity > 0.6) return Colors.primary[700];
        if (intensity > 0.4) return Colors.primary[500];
        if (intensity > 0.2) return Colors.primary[300];
        return Colors.primary[100];
    };

    const isSelected = (date: Date) => isSameDay(date, selectedDate);

    // Padding for start of month
    const startDay = getDay(startOfMonth(month)); // 0 = Sunday
    const emptyDays = Array(startDay).fill(null);

    return (
        <View style={styles.container}>
            <View style={styles.grid}>
                {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map((d, i) => (
                    <Text key={i} style={styles.dayLabel}>{d}</Text>
                ))}

                {emptyDays.map((_, i) => (
                    <View key={`empty-${i}`} style={styles.cell} />
                ))}

                {days.map((day: Date, i: number) => (
                    <TouchableOpacity
                        key={i}
                        style={[
                            styles.cell,
                            { backgroundColor: getIntensityColor(day) },
                            isSelected(day) && styles.selectedCell
                        ]}
                        onPress={() => onDayPress(day)}
                    >
                        <Text style={[
                            styles.dayText,
                            isSelected(day) && styles.selectedDayText,
                            dailyMap.get(format(day, 'yyyy-MM-dd')) ? { color: Colors.gray[900] } : { color: Colors.gray[400] },
                            // White text for dark backgrounds
                            ((dailyMap.get(format(day, 'yyyy-MM-dd')) || 0) / (maxSpend || 1)) > 0.4 && { color: 'white' }
                        ]}>
                            {format(day, 'd')}
                        </Text>
                    </TouchableOpacity>
                ))}
            </View>

            <View style={styles.legend}>
                <Text style={styles.legendLabel}>Less</Text>
                <View style={[styles.legendDot, { backgroundColor: Colors.primary[100] }]} />
                <View style={[styles.legendDot, { backgroundColor: Colors.primary[300] }]} />
                <View style={[styles.legendDot, { backgroundColor: Colors.primary[500] }]} />
                <View style={[styles.legendDot, { backgroundColor: Colors.primary[700] }]} />
                <View style={[styles.legendDot, { backgroundColor: Colors.primary[900] }]} />
                <Text style={styles.legendLabel}>More</Text>
            </View>
        </View>
    );
};

const styles = StyleSheet.create({
    container: {
        marginBottom: 20,
    },
    grid: {
        flexDirection: 'row',
        flexWrap: 'wrap',
    },
    dayLabel: {
        width: cellSize,
        textAlign: 'center',
        marginBottom: 8,
        color: Colors.gray[500],
        fontSize: 12,
        fontWeight: '600',
    },
    cell: {
        width: cellSize,
        height: cellSize * 0.8, // Slightly shorter for density
        justifyContent: 'center',
        alignItems: 'center',
        marginBottom: 4,
        borderRadius: 8,
        borderWidth: 2,
        borderColor: 'transparent',
    },
    selectedCell: {
        borderColor: Colors.warning[500], // Highlight border for selection
        transform: [{ scale: 1.1 }],
        zIndex: 1,
    },
    dayText: {
        fontSize: 12,
        fontWeight: '600',
    },
    selectedDayText: {
        fontWeight: '800',
    },
    legend: {
        flexDirection: 'row',
        justifyContent: 'flex-end',
        alignItems: 'center',
        marginTop: 10,
        paddingRight: 10,
    },
    legendDot: {
        width: 12,
        height: 12,
        borderRadius: 4,
        marginHorizontal: 2,
    },
    legendLabel: {
        fontSize: 10,
        color: Colors.gray[500],
        marginHorizontal: 4,
    },
});

import React, { useState, useEffect } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, ActivityIndicator } from 'react-native';
import { TrendLineChart } from './AnalysisCharts';
import { getMonthlyTrendInRange } from '../services/analysis';
import { Colors, Layout } from '../constants/Theme';
import { startOfMonth, subMonths, startOfYear, endOfMonth } from 'date-fns';
import { IconSymbol } from './ui/icon-symbol';

export const MonthlyTrendSection: React.FC = () => {
    const [range, setRange] = useState<'6M' | '12M' | 'YTD'>('6M');
    const [data, setData] = useState<{ month: string, total: number }[]>([]);
    const [loading, setLoading] = useState(true);
    const [comparison, setComparison] = useState<{ diff: number, percent: number, direction: 'up' | 'down' | 'same' } | null>(null);

    const loadData = async () => {
        setLoading(true);
        const now = new Date();
        let start: Date;

        if (range === '6M') {
            start = startOfMonth(subMonths(now, 5)); // Current + previous 5 = 6 months
        } else if (range === '12M') {
            start = startOfMonth(subMonths(now, 11));
        } else {
            start = startOfYear(now);
        }

        const end = endOfMonth(now);

        try {
            const trend = await getMonthlyTrendInRange(start, end);
            setData(trend);

            // Calculate comparison (Last month vs Previous month)
            if (trend.length >= 2) {
                const last = trend[trend.length - 1].total;
                const prev = trend[trend.length - 2].total;
                const diff = last - prev;
                const percent = prev !== 0 ? (Math.abs(diff) / prev) * 100 : 0;

                setComparison({
                    diff,
                    percent,
                    direction: diff > 0 ? 'up' : diff < 0 ? 'down' : 'same'
                });
            } else {
                setComparison(null);
            }

        } catch (e) {
            console.error("Failed to load monthly trend", e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadData();
    }, [loadData, range]);

    const renderComparison = () => {
        if (!comparison) return null;

        const color = comparison.direction === 'down' ? Colors.success[500] : comparison.direction === 'up' ? Colors.danger[500] : Colors.gray[500];
        const icon = comparison.direction === 'down' ? 'arrow.down' : comparison.direction === 'up' ? 'arrow.up' : 'minus';

        return (
            <View style={styles.comparisonContainer}>
                <IconSymbol name={icon as any} size={16} color={color} />
                <Text style={[styles.comparisonText, { color }]}>
                    {comparison.percent.toFixed(1)}% {comparison.direction === 'down' ? 'saved' : 'more'} vs last month
                </Text>
            </View>
        );
    };

    return (
        <View style={styles.container}>
            <View style={styles.header}>
                <View>
                    <Text style={styles.title}>Monthly Expense Trends</Text>
                    {renderComparison()}
                </View>
            </View>

            <View style={styles.toggles}>
                {(['6M', '12M', 'YTD'] as const).map(r => (
                    <TouchableOpacity
                        key={r}
                        style={[styles.toggle, range === r && styles.toggleActive]}
                        onPress={() => setRange(r)}
                    >
                        <Text style={[styles.toggleText, range === r && styles.toggleTextActive]}>
                            {r === 'YTD' ? 'This Year' : `Last ${r}`}
                        </Text>
                    </TouchableOpacity>
                ))}
            </View>

            {loading ? (
                <View style={styles.loadingContainer}>
                    <ActivityIndicator color={Colors.primary[500]} />
                </View>
            ) : (
                <TrendLineChart data={data} type="monthly" />
            )}
        </View>
    );
};

const styles = StyleSheet.create({
    container: {
        backgroundColor: Colors.white,
        borderRadius: Layout.radius.lg,
        padding: Layout.spacing.lg,
        marginBottom: Layout.spacing.lg,
        ...Layout.shadows.sm,
    },
    header: {
        flexDirection: 'row',
        justifyContent: 'space-between',
        alignItems: 'flex-start',
        marginBottom: 16,
    },
    title: {
        fontSize: 18,
        fontWeight: '700',
        color: Colors.gray[900],
        marginBottom: 4,
    },
    comparisonContainer: {
        flexDirection: 'row',
        alignItems: 'center',
        gap: 4,
    },
    comparisonText: {
        fontSize: 12,
        fontWeight: '600',
    },
    toggles: {
        flexDirection: 'row',
        backgroundColor: Colors.gray[100],
        borderRadius: 8,
        padding: 4,
        marginBottom: 20,
        alignSelf: 'flex-start',
    },
    toggle: {
        paddingVertical: 6,
        paddingHorizontal: 12,
        borderRadius: 6,
    },
    toggleActive: {
        backgroundColor: Colors.white,
        shadowColor: "#000",
        shadowOffset: { width: 0, height: 1 },
        shadowOpacity: 0.1,
        shadowRadius: 1,
        elevation: 1,
    },
    toggleText: {
        fontSize: 12,
        fontWeight: '600',
        color: Colors.gray[500],
    },
    toggleTextActive: {
        color: Colors.gray[900],
    },
    loadingContainer: {
        height: 220,
        justifyContent: 'center',
        alignItems: 'center',
    }
});

import React, { useState } from 'react';
import { 
  View, 
  Text, 
  StyleSheet, 
  Modal, 
  TouchableOpacity, 
  TouchableWithoutFeedback, 
  Dimensions 
} from 'react-native';
import { Colors, Typography, Layout } from '../constants/Theme';
import { PressableScale } from './ui/PressableScale';
import { Repeat, X } from 'lucide-react-native';

const { _height } = Dimensions.get('window');

interface RecurringBottomSheetProps {
  visible: boolean;
  onClose: () => void;
  transaction: { 
    amount: number; 
    category: string; 
    subcategory: string; 
    account_id: number; 
    description: string 
  } | null;
  onSave: (frequency: 'monthly' | 'quarterly' | 'yearly' | 'custom') => void;
}

export const RecurringBottomSheet: React.FC<RecurringBottomSheetProps> = ({
  visible,
  onClose,
  transaction,
  onSave
}) => {
  const [selectedFreq, setSelectedFreq] = useState<'monthly' | 'quarterly' | 'yearly' | 'custom'>('monthly');

  if (!transaction) return null;

  const frequencies: { label: string; value: 'monthly' | 'quarterly' | 'yearly' | 'custom' }[] = [
    { label: 'Custom/Daily', value: 'custom' },
    { label: 'Quarterly', value: 'quarterly' },
    { label: 'Monthly', value: 'monthly' },
    { label: 'Yearly', value: 'yearly' },
  ];

  return (
    <Modal
      visible={visible}
      transparent
      animationType="slide"
      onRequestClose={onClose}
    >
      <TouchableWithoutFeedback onPress={onClose}>
        <View style={styles.overlay}>
          <TouchableWithoutFeedback>
            <View style={styles.content}>
              <View style={styles.header}>
                <View style={styles.titleRow}>
                  <View style={styles.iconContainer}>
                    <Repeat size={20} color={Colors.primary[600]} />
                  </View>
                  <Text style={styles.title}>Repeat Transaction</Text>
                </View>
                <TouchableOpacity onPress={onClose} style={styles.closeBtn}>
