        width: '100%',
        backgroundColor: 'rgba(255,255,255,0.1)',
        position: 'absolute',
        bottom: 0,
        left: 0,
    },
    progressBar: {
        height: '100%',
        backgroundColor: Colors.primary[500],
    }
});

import React, { useRef } from 'react';
import { View, Text, TouchableOpacity, StyleSheet, Animated } from 'react-native';
import { Swipeable } from 'react-native-gesture-handler';
import { Trash2, Edit2, Copy, Repeat } from 'lucide-react-native';
import {  Typography } from '../constants/Theme';

interface SwipeableRowProps {
  children: React.ReactNode;
  onDelete?: () => void;
  onEdit?: () => void;
  onDuplicate?: () => void;
  onRepeat?: () => void;
  deleteConfirmTitle?: string;
  deleteConfirmMessage?: string;
}

export const SwipeableRow: React.FC<SwipeableRowProps> = ({
  children,
  onDelete,
  onEdit,
  onDuplicate,
  onRepeat,
  deleteConfirmTitle = "Delete Item",
  deleteConfirmMessage = "Are you sure you want to delete this?"
}) => {
  const swipeableRef = useRef<Swipeable>(null);

  const renderRightActions = (
    progress: Animated.AnimatedInterpolation<number>,
    dragX: Animated.AnimatedInterpolation<number>
  ) => {
    const _trans = dragX.interpolate({
      inputRange: [-144, 0],
      outputRange: [0, 144],
    });

    return (
      <View style={{ width: 144, flexDirection: 'row' }}>
        <Animated.View style={{ flex: 1, transform: [{ translateX: 0 }] }}>
          <TouchableOpacity 
            style={[styles.action, { backgroundColor: '#2D6EF5' }]}
            onPress={() => { 
              swipeableRef.current?.close(); 
              onEdit?.(); 
            }}
          >
            <Edit2 size={20} color="white" />
            <Text style={styles.actionLabel}>Edit</Text>
          </TouchableOpacity>
        </Animated.View>
        <Animated.View style={{ flex: 1, transform: [{ translateX: 0 }] }}>
          <TouchableOpacity 
            style={[styles.action, { backgroundColor: '#F04438' }]}
            onPress={() => {
              swipeableRef.current?.close();
              onDelete?.();
            }}
          >
            <Trash2 size={20} color="white" />
            <Text style={styles.actionLabel}>Delete</Text>
          </TouchableOpacity>
        </Animated.View>
      </View>
    );
  };

  const renderLeftActions = (
    progress: Animated.AnimatedInterpolation<number>,
    dragX: Animated.AnimatedInterpolation<number>
  ) => {
    return (
      <View style={{ width: 152, flexDirection: 'row' }}>
         <TouchableOpacity 
          style={[styles.action, { backgroundColor: '#12B76A', width: 72 }]}
          onPress={() => { 
            swipeableRef.current?.close(); 
            onDuplicate?.(); 
          }}
        >
          <Copy size={20} color="white" />
          <Text style={styles.actionLabel}>Copy</Text>
        </TouchableOpacity>
        <TouchableOpacity 
          style={[styles.action, { backgroundColor: '#6941C6', width: 80 }]}
          onPress={() => { 
            swipeableRef.current?.close(); 
            onRepeat?.(); 
          }}
        >
          <Repeat size={20} color="white" />
          <Text style={styles.actionLabel}>Repeat</Text>
        </TouchableOpacity>
      </View>
    );
  };

  return (
    <Swipeable
      ref={swipeableRef}
      friction={2}
      leftThreshold={30}
      rightThreshold={40}
      renderLeftActions={renderLeftActions}
      renderRightActions={renderRightActions}
      overshootFriction={8}
    >
      {children}
    </Swipeable>
  );
};

const styles = StyleSheet.create({
  action: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    height: '100%',
  },
  actionLabel: {
    color: 'white',
    fontSize: 10,
    fontFamily: Typography.family.bold,
    marginTop: 4,
    textTransform: 'uppercase',
  },
});

import React from 'react';
import { View, Text, TouchableOpacity, StyleSheet, Dimensions } from 'react-native';
import { Delete, Check } from 'lucide-react-native';
import { Colors, Layout } from '../../constants/Theme';

interface KeypadProps {
    onPress: (val: string) => void;
    onDelete: () => void;
    onSubmit: () => void;
    onClear: () => void;
    onEvaluate?: () => void;
    disabled?: boolean;
    submitColor?: string;
    submitLabel?: string;
}

export const Keypad: React.FC<KeypadProps> = ({
    onPress,
    onDelete,
    onSubmit,
    onClear,
    onEvaluate,
    disabled,
    submitColor,
    submitLabel = "Save Expense"
}) => {
    const keys = [
        '7', '8', '9', '/',
        '4', '5', '6', '*',
        '1', '2', '3', '-',
        '.', '0', 'C', '+'
    ];

    const handlePress = (key: string) => {
        if (key === 'C') {
            onClear();
        } else {
            onPress(key);
        }
    };

    const handleDelete = () => {
        onDelete();
    };

    const handleSubmit = () => {
        onSubmit();
    };

    return (
        <View style={styles.container}>
            <View style={styles.grid}>
                {keys.map((key) => {
                    const isOp = ['/', '*', '-', '+', 'C'].includes(key);
                    return (
                        <TouchableOpacity
                            key={key}
                            style={[styles.key, isOp && styles.opKey]}
                            onPress={() => handlePress(key)}
                            activeOpacity={0.6}
                        >
                            <Text style={[styles.keyText, isOp && styles.opKeyText]}>{key}</Text>
                        </TouchableOpacity>
                    );
                })}
            </View>

            <View style={styles.actionsRow}>
                <TouchableOpacity
                    style={[styles.actionKey, styles.circleActionKey, { backgroundColor: Colors.danger[50] }]}
                    onPress={handleDelete}
                    onLongPress={onClear}
                >
                    <Delete size={24} color={Colors.danger[500]} />
                </TouchableOpacity>

                {onEvaluate && (
                    <TouchableOpacity
                        style={[
                            styles.actionKey,
                            styles.circleActionKey,
                            { 
                                borderColor: Colors.primary[600], 
                                borderWidth: 1, 
                                backgroundColor: Colors.white,
                                marginLeft: 16
                            }
                        ]}
                        onPress={onEvaluate}
                    >
                        <Text style={[styles.keyText, { color: Colors.primary[600] }]}>=</Text>
                    </TouchableOpacity>
                )}

                <TouchableOpacity
                    style={[
                        styles.actionKey,
                        styles.submitKey,
                        { backgroundColor: submitColor || Colors.primary[600] },
                        disabled && styles.disabledKey
                    ]}
                    onPress={handleSubmit}
                    disabled={disabled}
                >
                    <Text style={styles.submitText}>{submitLabel}</Text>
                    <Check size={20} color={Colors.white} />
                </TouchableOpacity>
            </View>
        </View>
    );
};

const windowWidth = Dimensions.get('window').width;
const keySize = (windowWidth - 48) / 4; // 4 cols, padding

const styles = StyleSheet.create({
    container: {
