import React, { createContext, useContext, useEffect, useState } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';
import {
    initDatabase,
    getTransactions,
    getAccounts,
    getCategories,
    Transaction,
    Account,
    CategoryNode
} from '../services/database';

interface AppContextType {
    transactions: Transaction[];
    accounts: Account[];
    categories: CategoryNode[];
    loading: boolean;
    soundEnabled: boolean;
    refreshData: () => Promise<void>;
    setSoundEnabled: (enabled: boolean) => Promise<void>;
}

const AppContext = createContext<AppContextType>({
    transactions: [],
    accounts: [],
    categories: [],
    loading: true,
    soundEnabled: true,
    refreshData: async () => { },
    setSoundEnabled: async () => { },
});

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [transactions, setTransactions] = useState<Transaction[]>([]);
    const [accounts, setAccounts] = useState<Account[]>([]);
    const [categories, setCategories] = useState<CategoryNode[]>([]);
    const [loading, setLoading] = useState(true);
    const [soundEnabled, setSoundEnabledState] = useState(true);

    const refreshData = async () => {
        try {
            const [txs, accs, cats] = await Promise.all([
                getTransactions(),
                getAccounts(),
                getCategories()
            ]);
            setTransactions(txs);
            setAccounts(accs);
            setCategories(cats);
        } catch (error) {
            console.error("Failed to fetch data", error);
        }
    };

    const setSoundEnabled = async (enabled: boolean) => {
        try {
            setSoundEnabledState(enabled);
            await AsyncStorage.setItem('sound_enabled', enabled ? 'true' : 'false');
        } catch (error) {
            console.error("Failed to save sound setting", error);
        }
    };

    useEffect(() => {
        const init = async () => {
            await initDatabase();

            // Load sound setting
            try {
                const savedSound = await AsyncStorage.getItem('sound_enabled');
                if (savedSound !== null) {
                    setSoundEnabledState(savedSound === 'true');
                }
            } catch (e) {
                console.error("Error loading sound preference", e);
            }

            await refreshData();
            setLoading(false);
        };
        init();
    }, []);

    return (
        <AppContext.Provider value={{
            transactions,
            accounts,
            categories,
            loading,
            soundEnabled,
            refreshData,
            setSoundEnabled
        }}>
            {children}
        </AppContext.Provider>
    );
};

export const useApp = () => useContext(AppContext);

import { getDatabase, initDatabase } from '../services/database';
import { getMergedClassifications } from './categoryClassification';
import { startOfMonth, endOfMonth, subMonths, subWeeks } from 'date-fns';

export interface SatisfactionMetrics {
  totalIncome: number;
  totalExpense: number;
  essentialExpense: number;
  nonEssentialExpense: number;
  remainingBalance: number;
  savingsRate: number;
  essentialRatio: number;
  luxuryRatio: number;
  consistencyScore: number;
  balanceStability: number;
  baseScore: number;
  currentMonthBalance: number;
  previousMonthBalance: number;
  penalties: { reason: string, points: number }[];
  bonuses: { reason: string, points: number }[];
}

export interface SatisfactionStatus {
  label: string;
  color: string;
  emoji: string;
  description: string;
}

export interface SatisfactionResult {
  finalScore: number;
  status: SatisfactionStatus;
  metrics: SatisfactionMetrics;
}

const ensureDb = async () => {
    await initDatabase();
    return getDatabase();
};

export const SatisfactionEngine = {
  compute: async (period: string = 'month'): Promise<SatisfactionResult> => {
    const db = await ensureDb();
    const classifications = await getMergedClassifications();
    const now = new Date();

    // Determine current period bounds
    // Based on user prompt: "For the selected period (default: current calendar month)"
    const start = startOfMonth(now).toISOString();
    const end = endOfMonth(now).toISOString();

    // Get current month transactions
    const query = `
      SELECT amount, category, date 
      FROM transactions 
      WHERE date >= ? AND date <= ? AND category != 'Transfer' AND category != 'Debt/Credit'
    `;
    const transactions = await db.getAllAsync<{ amount: number, category: string, date: string }>(query, [start, end]);

    // 1. Core Metrics
    let totalIncome = 0;
    let totalExpense = 0;
    let essentialExpense = 0;
    let nonEssentialExpense = 0;

    transactions.forEach(t => {
      if (t.category === 'Income') {
        totalIncome += t.amount;
      } else {
        totalExpense += t.amount;
        const type = classifications[t.category] || 'non-essential';
        if (type === 'essential') {
          essentialExpense += t.amount;
        } else {
          nonEssentialExpense += t.amount;
        }
      }
    });

    // Early exit: no data at all
    if (totalIncome === 0 && totalExpense === 0) {
      return {
        finalScore: 0,
        status: {
          label: 'No Data',
          color: '#9CA3AF', 
          emoji: '📭',
          description: 'No transactions recorded this month',
        },
        metrics: {
          totalIncome: 0,
          totalExpense: 0,
          essentialExpense: 0,
          nonEssentialExpense: 0,
          remainingBalance: 0,
          savingsRate: 0,
          essentialRatio: 0,
          luxuryRatio: 0,
          consistencyScore: 0.5,
          balanceStability: 0.5,
          baseScore: 0,
          currentMonthBalance: 0,
          previousMonthBalance: 0,
          penalties: [],
          bonuses: []
        }
      };
    }

    const remainingBalance = totalIncome - totalExpense;
    const savingsRate = totalIncome > 0 ? remainingBalance / totalIncome : 0;
    const essentialRatio = totalExpense > 0 ? essentialExpense / totalExpense : 0;
    const luxuryRatio = totalExpense > 0 ? nonEssentialExpense / totalExpense : 0;

    // 2. Consistency Score (last 4 weeks)
    // We get last 4 weeks data ending today to calculate consistency
    const fourWeeksAgo = subWeeks(now, 4).toISOString();
    const weeklyQuery = `
      SELECT amount, date 
      FROM transactions 
      WHERE date >= ? AND date <= ? AND category != 'Income' AND category != 'Transfer' AND category != 'Debt/Credit'
    `;
    const weeklyTransactions = await db.getAllAsync<{ amount: number, date: string }>(weeklyQuery, [fourWeeksAgo, now.toISOString()]);

    // Bucket into 4 weeks
    const weeklyExpenses = [0, 0, 0, 0];
    weeklyTransactions.forEach(t => {
      const tDate = new Date(t.date);
      const diffTime = Math.abs(now.getTime() - tDate.getTime());
      const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));
      const weekIndex = Math.min(3, Math.floor(diffDays / 7));
      weeklyExpenses[weekIndex] += t.amount;
    });

    let consistencyScore = 0.5; // neutral default
    // If fewer than 2 weeks of data, default to 0.5
    const activeWeeks = weeklyExpenses.filter(w => w > 0).length;
    if (activeWeeks >= 2) {
      const mean = weeklyExpenses.reduce((a, b) => a + b, 0) / 4;
      if (mean > 0) {
        const variance = weeklyExpenses.reduce((acc, val) => acc + Math.pow(val - mean, 2), 0) / 4;
        consistencyScore = 1 - Math.min(variance / (mean * mean), 1);
      }
    }

    // 3. Balance Stability
    const prevMonth = subMonths(now, 1);
    const prevStart = startOfMonth(prevMonth).toISOString();
    const prevEnd = endOfMonth(prevMonth).toISOString();

    const prevQuery = `
      SELECT amount, category 
      FROM transactions 
      WHERE date >= ? AND date <= ? AND category != 'Transfer' AND category != 'Debt/Credit'
    `;
    const prevTransactions = await db.getAllAsync<{ amount: number, category: string }>(prevQuery, [prevStart, prevEnd]);

    let prevIncome = 0;
    let prevExpense = 0;
    prevTransactions.forEach(t => {
      if (t.category === 'Income') prevIncome += t.amount;
      else prevExpense += t.amount;
    });

    const previousMonthBalance = prevIncome - prevExpense;
    const currentMonthBalance = remainingBalance;

    let balanceStability = 0.5;
    if (prevTransactions.length > 0 && previousMonthBalance !== 0) {
      balanceStability = currentMonthBalance >= previousMonthBalance
        ? 1
        : Math.max(0, currentMonthBalance / previousMonthBalance);
    } else if (prevTransactions.length > 0 && previousMonthBalance === 0) {
      balanceStability = currentMonthBalance >= 0 ? 1 : 0;
    }

    // 4. Base Score Formula
    const baseScore = 
      (Math.min(Math.max(savingsRate, 0), 1) * 40) +
      (essentialRatio * 20) +
      (balanceStability * 20) +
      (consistencyScore * 20);

    // 5. Penalties and Bonuses
    let penaltyPoints = 0;
    let bonusPoints = 0;
    const penalties: { reason: string, points: number }[] = [];
    const bonuses: { reason: string, points: number }[] = [];

    // PENALTIES
    if (totalExpense > totalIncome && totalIncome > 0) {
      const pts = Math.round(Math.min(((totalExpense - totalIncome) / totalIncome) * 30, 30));
      if (pts > 0) {
        penaltyPoints += pts;
        penalties.push({ reason: 'Overspending detected', points: pts });
      }
    }

    if (luxuryRatio > 0.4) {
      const pts = Math.round((luxuryRatio - 0.4) * 25);
      if (pts > 0) {
        penaltyPoints += pts;
        penalties.push({ reason: 'High non-essential spending', points: pts });
      }
    }

    if (remainingBalance < 0) {
      penaltyPoints += 15;
      penalties.push({ reason: 'Negative balance', points: 15 });
    } else if (totalIncome > 0 && remainingBalance < totalIncome * 0.1) {
      penaltyPoints += 8;
      penalties.push({ reason: 'Low remaining balance (<10%)', points: 8 });
    }

    if (totalIncome === 0 && totalExpense > 0) {
      penaltyPoints += 20;
      penalties.push({ reason: 'Spending with zero income', points: 20 });
    }

    // BONUSES
    if (savingsRate >= 0.3) {
      let pts = 8;
      if (savingsRate >= 0.5) pts += 5;
      bonusPoints += pts;
      bonuses.push({ reason: 'Strong savings rate', points: pts });
    }

    if (luxuryRatio < 0.15 && totalExpense > 0) {
      bonusPoints += 5;
      bonuses.push({ reason: 'Controlled luxury spending', points: 5 });
    }

    if (consistencyScore > 0.85) {
      bonusPoints += 5;
      bonuses.push({ reason: 'Highly consistent spending pattern', points: 5 });
    }

    if (prevTransactions.length > 0 && currentMonthBalance > previousMonthBalance * 1.1) {
      bonusPoints += 5;
      bonuses.push({ reason: 'Positive balance growth vs last month', points: 5 });
    }

    // Final Score
    const finalScore = Math.round(Math.max(0, Math.min(100, baseScore - penaltyPoints + bonusPoints)));

    // Status Classification
    let status: SatisfactionStatus;
    if (finalScore < 30) {
      status = { label: 'Risky', color: '#F04438', emoji: '⚠️', description: 'Your finances need immediate attention' };
    } else if (finalScore < 50) {
      status = { label: 'Moderate', color: '#F79009', emoji: '📊', description: 'Some areas need improvement' };
    } else if (finalScore < 70) {
      status = { label: 'Balanced', color: '#0BA5EC', emoji: '⚖️', description: 'You are managing reasonably well' };
    } else if (finalScore < 85) {
      status = { label: 'Healthy', color: '#12B76A', emoji: '💚', description: 'Great financial discipline' };
    } else {
      status = { label: 'Optimal', color: '#6941C6', emoji: '🏆', description: 'Excellent financial health' };
    }

    const metrics: SatisfactionMetrics = {
      totalIncome,
      totalExpense,
      essentialExpense,
      nonEssentialExpense,
      remainingBalance,
      savingsRate,
      essentialRatio,
      luxuryRatio,
      consistencyScore,
      balanceStability,
      baseScore,
      currentMonthBalance,
      previousMonthBalance,
      penalties,
      bonuses
    };

    return {
      finalScore,
      status,
      metrics
    };
  }
};

// Chit Fund Computation Engine
// All computations are pure JavaScript - no SQLite writes

export interface ChitFund {
  id: number;
  name: string;
  total_members: number;
  monthly_amount: number;
  total_pot: number;
  duration_months: number;
  start_date: string;
  foreman_commission: number;
  status: 'active' | 'completed' | 'cancelled';
  my_turn_month: number | null;
  notes: string | null;
  created_at: string;
}

export interface ChitMonthlyRecord {
  id: number;
  chit_id: number;
  month_number: number;
  month_date: string;
  amount_paid: number | null;
  payment_date: string | null;
  payment_status: 'pending' | 'paid' | 'missed';
  winner_name: string | null;
  winner_is_me: number;
  bid_amount: number | null;
  pot_amount: number | null;
  commission_deducted: number | null;
  net_received: number | null;
  dividend_received: number | null;
  account_id: number | null;
  notes: string | null;
  created_at: string;
}

export interface ChitMember {
  id: number;
  chit_id: number;
  member_name: string;
  member_turn_month: number | null;
  notes: string | null;
}

export interface ChitCalculation {
  totalInvested: number;
  totalReceived: number;
  netPosition: number;
  monthsPaid: number;
  monthsRemaining: number;
  nextMonthDue: number | null;
  myTurnStatus: 'upcoming' | 'completed' | 'not_assigned' | 'passed';
  roi: number;
  annualizedRoi: number;
  bestMonth?: {
    monthNumber: number;
    netReceived: number;
    roi: number;
  };
  worstMonth?: {
    monthNumber: number;
    netReceived: number;
    roi: number;
  };
}

// --- CHIT FUND CALCULATIONS ---

export const calculateChitFundPosition = (
  chitFund: ChitFund,
  monthlyRecords: ChitMonthlyRecord[]
): ChitCalculation => {
  const paidRecords = monthlyRecords.filter(r => r.payment_status === 'paid');
  const myPaidRecords = paidRecords.filter(r => r.amount_paid !== null);

  // Calculate total invested
  const totalInvested = myPaidRecords.reduce((sum, record) => sum + (record.amount_paid || 0), 0);

  // Calculate total received
  const myWonRecords = monthlyRecords.filter(r => r.winner_is_me === 1 && r.net_received !== null);
  const totalReceived = myWonRecords.reduce((sum, record) => sum + (record.net_received || 0), 0);

  // Calculate net position
  const netPosition = totalReceived - totalInvested;

  // Calculate months paid and remaining
  const monthsPaid = myPaidRecords.length;
  const monthsRemaining = chitFund.duration_months - monthsPaid;

  // Find next month due
  const nextMonthDue = monthlyRecords
    .filter(r => r.payment_status === 'pending')
    .sort((a, b) => a.month_number - b.month_number)[0]?.month_number || null;

  // Determine my turn status
  let myTurnStatus: ChitCalculation['myTurnStatus'] = 'not_assigned';
  if (chitFund.my_turn_month !== null) {
    const currentMonth = new Date().getMonth() + 1;
    if (chitFund.my_turn_month < currentMonth) {
      myTurnStatus = 'passed';
    } else if (chitFund.my_turn_month === currentMonth) {
      myTurnStatus = 'upcoming';
    } else {
      myTurnStatus = 'upcoming';
    }

    // Check if I already won
    const myWonRecord = monthlyRecords.find(r => r.winner_is_me === 1);
    if (myWonRecord) {
      myTurnStatus = 'completed';
    }
  }

  // Calculate ROI
  const roi = totalInvested > 0 ? ((totalReceived - totalInvested) / totalInvested) * 100 : 0;

  // Calculate annualized ROI
  const elapsedMonths = monthsPaid;
  const annualizedRoi = elapsedMonths > 0 ? (roi / elapsedMonths) * 12 : 0;

  // Find best and worst months
  const completedRecords = monthlyRecords.filter(r => r.winner_name !== null && r.net_received !== null);

  let bestMonth, worstMonth;
  if (completedRecords.length > 0) {
    const monthCalculations = completedRecords.map(record => ({
      monthNumber: record.month_number,
      netReceived: record.net_received!,
      roi: record.amount_paid ? ((record.net_received! - record.amount_paid) / record.amount_paid) * 100 : 0
    }));

    bestMonth = monthCalculations.reduce((best, current) => 
      current.roi > best.roi ? current : best
    );

    worstMonth = monthCalculations.reduce((worst, current) => 
      current.roi < worst.roi ? current : worst
    );
  }

  return {
    totalInvested,
    totalReceived,
    netPosition,
    monthsPaid,
    monthsRemaining,
    nextMonthDue,
    myTurnStatus,
    roi,
    annualizedRoi,
    bestMonth,
    worstMonth
  };
};

// --- MONTHLY RECORD CALCULATIONS ---

export const calculateMonthlyPot = (
  chitFund: ChitFund,
  monthNumber: number,
  bidAmount: number | null
): { grossPot: number; commission: number; netPot: number } => {
  const grossPot = chitFund.monthly_amount * chitFund.total_members;
  const commission = grossPot * (chitFund.foreman_commission / 100);
  const netPot = grossPot - commission;

  return {
    grossPot,
    commission,
    netPot
  };
};

export const calculateWinnerNetAmount = (
  chitFund: ChitFund,
  monthNumber: number,
  bidAmount: number | null,
  winnerPaidAmount: number | null
): { grossReceived: number; commissionDeducted: number; netReceived: number; dividend: number } => {
  const { _grossPot, _commission, netPot } = calculateMonthlyPot(chitFund, monthNumber, bidAmount);

  let grossReceived = netPot;
  let commissionDeducted = 0;
  let dividend = 0;

  if (bidAmount !== null && bidAmount > 0) {
    // In a bidding chit, the winner gets the net pot minus bid amount
    grossReceived = netPot - bidAmount;
    commissionDeducted = bidAmount * (chitFund.foreman_commission / 100);
    dividend = bidAmount - commissionDeducted;
  }

  const netReceived = grossReceived - commissionDeducted;

  return {
    grossReceived,
    commissionDeducted,
    netReceived,
    dividend
  };
};

// --- CHIT FUND PROJECTIONS ---

export const calculateChitFundProjection = (
  chitFund: ChitFund,
  monthlyRecords: ChitMonthlyRecord[],
  assumedBidAmount: number = 0
): {
  projectedTotalInvestment: number;
  projectedTotalReturn: number;
  projectedNetPosition: number;
  projectedRoi: number;
  monthsToComplete: number;
} => {
  const paidMonths = monthlyRecords.filter(r => r.payment_status === 'paid').length;
  const remainingMonths = chitFund.duration_months - paidMonths;

  // Projected total investment
  const projectedTotalInvestment = chitFund.monthly_amount * chitFund.duration_months;

  // Calculate projected return based on when I expect to win
  let projectedTotalReturn = 0;

  if (chitFund.my_turn_month !== null) {
    const myTurnRecord = monthlyRecords.find(r => r.month_number === chitFund.my_turn_month);
    if (myTurnRecord && myTurnRecord.net_received !== null) {
      // I already won
      projectedTotalReturn = myTurnRecord.net_received;
    } else {
      // I will win in my turn month
      const { netReceived } = calculateWinnerNetAmount(
        chitFund,
        chitFund.my_turn_month,
        assumedBidAmount,
        chitFund.monthly_amount
      );
      projectedTotalReturn = netReceived;
    }
  } else {
    // No assigned turn, assume average return
    const avgMonthlyReturn = (chitFund.monthly_amount * chitFund.total_members * (1 - chitFund.foreman_commission / 100)) / chitFund.total_members;
    projectedTotalReturn = avgMonthlyReturn;
  }

  const projectedNetPosition = projectedTotalReturn - projectedTotalInvestment;
  const projectedRoi = projectedTotalInvestment > 0 ? (projectedNetPosition / projectedTotalInvestment) * 100 : 0;

  return {
    projectedTotalInvestment,
    projectedTotalReturn,
    projectedNetPosition,
    projectedRoi,
    monthsToComplete: remainingMonths
  };
};

// --- CHIT FUND ANALYSIS ---

export const analyzeChitFundPerformance = (
  chitFund: ChitFund,
  monthlyRecords: ChitMonthlyRecord[]
): {
  averageBidAmount: number;
  highestBidAmount: number;
  lowestBidAmount: number;
  biddingFrequency: number; // Percentage of months with bidding
  averageMonthlyReturn: number;
  volatilityIndex: number; // Standard deviation of returns
  paymentCompliance: number; // Percentage of payments made on time
} => {
  const completedRecords = monthlyRecords.filter(r => r.winner_name !== null);
  const biddingRecords = completedRecords.filter(r => r.bid_amount !== null && r.bid_amount > 0);

  // Bid analysis
  const bidAmounts = biddingRecords.map(r => r.bid_amount!);
  const averageBidAmount = bidAmounts.length > 0 ? bidAmounts.reduce((sum, bid) => sum + bid, 0) / bidAmounts.length : 0;
  const highestBidAmount = bidAmounts.length > 0 ? Math.max(...bidAmounts) : 0;
  const lowestBidAmount = bidAmounts.length > 0 ? Math.min(...bidAmounts) : 0;
  const biddingFrequency = completedRecords.length > 0 ? (biddingRecords.length / completedRecords.length) * 100 : 0;

  // Return analysis
  const monthlyReturns = completedRecords.map(r => r.net_received || 0);
  const averageMonthlyReturn = monthlyReturns.length > 0 ? monthlyReturns.reduce((sum, ret) => sum + ret, 0) / monthlyReturns.length : 0;

  // Volatility (standard deviation)
  const variance = monthlyReturns.length > 0 ? 
    monthlyReturns.reduce((sum, ret) => {
      const diff = ret - averageMonthlyReturn;
      return sum + (diff * diff);
    }, 0) / monthlyReturns.length : 0;
  const volatilityIndex = Math.sqrt(variance);

  // Payment compliance
  const expectedPayments = monthlyRecords.length;
  const actualPayments = monthlyRecords.filter(r => r.payment_status === 'paid').length;
  const paymentCompliance = expectedPayments > 0 ? (actualPayments / expectedPayments) * 100 : 0;

  return {
    averageBidAmount,
    highestBidAmount,
    lowestBidAmount,
    biddingFrequency,
    averageMonthlyReturn,
    volatilityIndex,
    paymentCompliance
  };
};

// --- CHIT FUND COMPARISON ---

export const compareChitFunds = (
  chitFunds: { chitFund: ChitFund; calculation: ChitCalculation }[]
): {
  bestPerforming: { chitFund: ChitFund; roi: number } | null;
  worstPerforming: { chitFund: ChitFund; roi: number } | null;
  highestInvestment: { chitFund: ChitFund; amount: number } | null;
  lowestInvestment: { chitFund: ChitFund; amount: number } | null;
  averageRoi: number;
  totalInvestment: number;
  totalReturn: number;
} => {
  if (chitFunds.length === 0) {
    return {
      bestPerforming: null,
      worstPerforming: null,
      highestInvestment: null,
      lowestInvestment: null,
      averageRoi: 0,
      totalInvestment: 0,
      totalReturn: 0
    };
  }

  // Find best and worst performing
  const bestPerforming = chitFunds.reduce((best, current) => 
    current.calculation.roi > best.calculation.roi ? current : best
  );

  const worstPerforming = chitFunds.reduce((worst, current) => 
    current.calculation.roi < worst.calculation.roi ? current : worst
  );

  // Find highest and lowest investment
  const highestInvestment = chitFunds.reduce((highest, current) => 
    current.calculation.totalInvested > highest.calculation.totalInvested ? current : highest
  );

  const lowestInvestment = chitFunds.reduce((lowest, current) => 
    current.calculation.totalInvested < lowest.calculation.totalInvested ? current : lowest
  );

  // Calculate averages and totals
  const totalInvestment = chitFunds.reduce((sum, current) => sum + current.calculation.totalInvested, 0);
  const totalReturn = chitFunds.reduce((sum, current) => sum + current.calculation.totalReceived, 0);
  const averageRoi = chitFunds.reduce((sum, current) => sum + current.calculation.roi, 0) / chitFunds.length;

  return {
    bestPerforming: { chitFund: bestPerforming.chitFund, roi: bestPerforming.calculation.roi },
    worstPerforming: { chitFund: worstPerforming.chitFund, roi: worstPerforming.calculation.roi },
    highestInvestment: { chitFund: highestInvestment.chitFund, amount: highestInvestment.calculation.totalInvested },
    lowestInvestment: { chitFund: lowestInvestment.chitFund, amount: lowestInvestment.calculation.totalInvested },
    averageRoi,
    totalInvestment,
    totalReturn
  };
};

// --- CHIT FUND RECOMMENDATIONS ---

export const generateChitFundRecommendations = (
  chitFund: ChitFund,
  calculation: ChitCalculation,
  analysis: ReturnType<typeof analyzeChitFundPerformance>
): {
  riskLevel: 'low' | 'medium' | 'high';
  recommendation: string;
  actionItems: string[];
} => {
  const riskLevel = calculation.roi > 10 ? 'low' : calculation.roi > 0 ? 'medium' : 'high';

  let recommendation = '';
  let actionItems: string[] = [];

  if (riskLevel === 'low') {
    recommendation = 'This chit fund is performing well with good returns.';
    actionItems = [
      'Continue regular payments',
      'Monitor monthly performance',
      'Consider reinvesting returns'
    ];
  } else if (riskLevel === 'medium') {
    recommendation = 'This chit fund has moderate returns. Monitor closely.';
    actionItems = [
      'Ensure timely payments',
      'Track bidding patterns',
      'Consider exit strategies if needed'
    ];
  } else {
    recommendation = 'This chit fund has poor returns. Review your participation.';
    actionItems = [
      'Review payment history',
      'Consider early exit options',
      'Evaluate alternative investments'
    ];
  }

  if (analysis.paymentCompliance < 80) {
    actionItems.push('Improve payment compliance - missing payments affects returns');
  }

  if (analysis.volatilityIndex > 1000) {
    actionItems.push('High volatility detected - be prepared for fluctuations');
  }

  return {
    riskLevel,
    recommendation,
    actionItems
  };
};

